  if(reset) 
  emon_reg[DW-1:0] <= {(DW){1'b1}}; 
  else if(reg_write) 
  emon_reg[DW-1:0] <= reg_data[DW-1:0]; 
  else 
  emon_reg[DW-1:0] <= emon_reg[DW-1:0] - {31'b0,emon_input}; 
  assign emon_zero_flag = ~(|emon_reg[DW-1:0]); 
 endmodule

