module mg_07256 (clk,rst,config_valid,config_low,config_high,config_chained,input_valid,input_char,prev_matched,this_matched);
input clk; 
  input rst; 
  input config_valid; 
  input [7:0] config_low; 
  input [7:0] config_high; 
  input [1:0] config_chained; 
  input input_valid; 
  input [7:0] input_char; 
  input prev_matched; 
  output this_matched; 
  reg char_match; 
  reg [7:0] char_low; 
  reg [7:0] char_high; 
  reg is_chained; 
  assign this_matched = char_match; 
  always @(posedge clk) 
  begin 
  if(rst) begin 
  char_low <= 0; 
  char_high <= 0; 
  char_match <= 0; 
  end 
  else begin 
  if (input_valid==1) begin 
  if (char_low<=input_char && char_high>input_char) 
  char_match <= is_chained ? prev_matched : 1; 
  else 
  char_match <= 0; 
  end 
  if (config_valid==1) begin 
  char_low <= config_low; 
  char_high <= config_high; 
  is_chained <= config_chained; 
  char_match <= 0; 
  end 
  end 
  end 
 endmodule

