   input                 clk_i           ,  
   input                 rstn_i          ,  
   output reg [ 23: 0]   dac_a_o         ,  
   output reg [ 23: 0]   dac_b_o         ,  
   output reg [ 23: 0]   dac_c_o         ,  
   output reg [ 23: 0]   dac_d_o         ,  
   input      [ 31: 0]   sys_addr        ,  
   input      [ 31: 0]   sys_wdata       ,  
   input                 sys_wen         ,  
   input                 sys_ren         ,  
   output reg [ 31: 0]   sys_rdata       ,  
   output reg            sys_err         ,  
   output reg            sys_ack            
);

always @(posedge clk_i)
if (rstn_i == 1'b0) begin
   dac_a_o     <= 24'h0F_0000 ;
   dac_b_o     <= 24'h4E_0000 ;
   dac_c_o     <= 24'h75_0000 ;
   dac_d_o     <= 24'h9C_0000 ;
