module origen_042137(q, q1, j, k, c);
    output reg q, q1;
    input j, k, c;

    initial begin
        q = 1'b0;
        q1 = 1'b1;
    end

    always @(posedge c) begin
        case ({j, k})
            2'b00: begin q <= q; q1 <= q1; end
            2'b01: begin q <= 1'b0; q1 <= 1'b1; end
            2'b10: begin q <= 1'b1; q1 <= 1'b0; end
            2'b11: begin q <= ~q; q1 <= ~q1; end
        endcase
    end
endmodule

