module rtlpp_09568 (
   readdata,
   bidir_port,
   address, clk, reset_n, write_n, writedata
   );

   parameter GPIO_WIDTH = 8;
   parameter GPIO_ADDR = 3;

   inout [GPIO_WIDTH-1:0] bidir_port;
   output [1:0] readdata;
   input [GPIO_ADDR-1:0] address;
   input clk;
   input reset_n;
   input write_n;
   input [1:0] writedata;

   reg [GPIO_WIDTH-1:0] data_mode;
   reg [GPIO_WIDTH-1:0] data_outz;
   reg [GPIO_WIDTH-1:0] data_mode_v;
   reg [GPIO_WIDTH-1:0] data_outz_v;
   reg [1:0] readdata;
   integer N;

   reg [GPIO_WIDTH-1:0] bidir_port_reg; // Register for bidir_port

   always @(data_mode or data_outz) begin
     for (N = 0; N <= (GPIO_WIDTH-1); N = N+1) begin
       bidir_port_reg[N] = data_mode[N] ? ~data_outz[N] : 1'bz;
     end
   end

   assign bidir_port = bidir_port_reg;

   always @(address or bidir_port_reg) begin
     readdata = {1'b0, bidir_port_reg[address]};
   end

   always @(address or data_outz or write_n or writedata) begin
     for (N = 0; N <= (GPIO_WIDTH-1); N = N+1) begin
       data_outz_v[N] = (~write_n & (address == N)) ? ~writedata[0] : data_outz[N];
     end
   end

   always @(address or data_mode or write_n or writedata) begin
     for (N = 0; N <= (GPIO_WIDTH-1); N = N+1) begin
       data_mode_v[N] = (~write_n & (address == N)) ? writedata[1] : data_mode[N];
     end
   end

   always @(posedge clk or negedge reset_n) begin
     if (reset_n == 0) begin
       data_outz <= 0;
       data_mode <= 0;
     end else begin
       data_outz <= data_outz_v;
       data_mode <= data_mode_v;
     end
   end

endmodule

