  o_full <= 1'b0; 
  end 
  else if( ~o_stall ) begin 
  if (enable) begin 
  if( (counter != 32'b0) && (counter == i_limit) ) begin 
  o_full <= 1'b1; 
  o_stall <= 1'b1; 
  o_resultvalid <= 1'b0; 
  end 
  else begin 
  o_result <= i_init + counter; 
  o_resultvalid <= 1'b1; 
  counter <= counter + i_increment; 
  end 
  end 
  else begin 
  o_resultvalid <= 1'b0; 
  end 
  end 
 end 
 endmodule

