                    s2 = 3'h2,
                    s3 = 3'h3,
                    s4 = 3'h4,
                    s5 = 3'h5,
                    s6 = 3'h6,
                    s7 = 3'h7;

   reg [2:0] st_reg, st_nxt;

   always @(posedge clk or negedge rst) begin
      if (!rst)
         st_reg <= s0;
      else
         st_reg <= st_nxt;
   end

   always @(*) begin
      st_nxt = st_reg;
      case (st_reg)
         s0: if (din)
                st_nxt = s1;
             else
                st_nxt = s4;
         s1: if (din)
                st_nxt = s1;
             else
                st_nxt = s2;
         s2: if (din)
                st_nxt = s3;
             else
                st_nxt = s5;
         s3: if (din)
                st_nxt = s1;
             else
                st_nxt = s2;
         s4: if (din)
                st_nxt = s1;
             else
                st_nxt = s5;
         s5: if (din)
                st_nxt = s6;
             else
                st_nxt = s5;
         s6: if (din)
                st_nxt = s1;
             else
                st_nxt = s7;
         s7: if (din)
                st_nxt = s3;
             else
                st_nxt = s5;
         default: st_nxt = s0;
      endcase 
   end 

   assign dout = (st_reg == s3 || st_reg == s7);

endmodule

