                             // Clock out ports
    output clk_out1,
    output clk_out2,
    // Status and control signals
    input  reset,
    input  clk_in1
);
  // Input buffering
  //------------------------------------
  wire clk_in1_clk_user_1;
  wire clk_in2_clk_user_1;
  IBUF clkin1_ibufg (
      .O(clk_in1_clk_user_1),
      .I(clk_in1)
