   reg 				 s_ready_o;
   reg 				 s_state;
   reg [4:0] 			 s_count;
   wire [23:0] 			 s_tem_prod;

   always @(posedge clk or posedge rst) 
     if (rst)
       begin 
	  s_fracta_i <= 'd0;
	  s_fractb_i <= 'd0;
	  s_signa_i <= 1'b0;
	  s_signb_i <= 1'b0;
	  s_start_i <= 1'b0;
       end
     else 
       begin
	  s_fracta_i <= fracta_i;
	  s_fractb_i <= fractb_i;
	  s_signa_i<= signa_i;
	  s_signb_i<= signb_i;
	  s_start_i <= start_i;
       end

   always @(posedge clk or posedge rst) 
     if (rst) 
       begin
	  fract_o <= 'd0;
	  sign_o <= 1'b0;
	  ready_o <= 1'b0;
       end
     else 
       begin
	  fract_o <= s_fract_o;
	  sign_o <= s_sign_o;	
