	    s_state <= t_state_waiting;
	    s_ready_o <= 1;
	    s_count <=0;
	 end
       else if (s_state==t_state_busy)
	 s_count <= s_count + 1;
       else
	 begin
	    s_state <= t_state_waiting;
	    s_ready_o <= 0;
