module rtlpp_06031 (

                                address,
                                chipselect,
                                clk,
                                reset_n,
                                write_n,
                                writedata,

                                irq,
                                readdata
                             );

  output           irq;
  output  [15:0]   readdata;
  input   [2:0]    address;
  input            chipselect;
  input            clk;
  input            reset_n;
  input            write_n;
  input   [15:0]   writedata;

  wire             clk_en;
  wire             control_continuous;
  wire             control_interrupt_enable;
  reg     [3:0]    control_register;
  wire             control_wr_strobe;
  reg              counter_is_running;
  wire             counter_is_zero;
  wire    [31:0]   counter_load_value;
  reg     [31:0]   counter_snapshot;
  reg              delayed_unxcounter_is_zeroxx0;
  wire             do_start_counter;
  wire             do_stop_counter;
  reg              force_reload;
  reg     [31:0]   internal_counter;
  reg     [15:0]   period_h_register;
  wire             period_h_wr_strobe;
  reg     [15:0]   period_l_register;
  wire             period_l_wr_strobe;
  wire    [15:0]   read_mux_out;
  reg     [15:0]   readdata;
  wire             snap_h_wr_strobe;
  wire             snap_l_wr_strobe;
  wire    [31:0]   snap_read_value;
  wire             snap_strobe;
  wire             start_strobe;
  wire             status_wr_strobe;
  wire             stop_strobe;
  wire             timeout_event;
  reg              timeout_occurred;

  assign clk_en = 1;

  always @(posedge clk or negedge reset_n) begin
    if (reset_n == 0)
        internal_counter <= 32'h31;
    else if (counter_is_running || force_reload) begin
        if (counter_is_zero || force_reload)
            internal_counter <= counter_load_value;
        else 
            internal_counter <= internal_counter - 1;
    end
  end

  assign counter_is_zero = internal_counter == 0;
  assign counter_load_value = {period_h_register, period_l_register};

  always @(posedge clk or negedge reset_n) begin
    if (reset_n == 0)
        force_reload <= 0;
    else if (clk_en)
        force_reload <= period_h_wr_strobe || period_l_wr_strobe;
  end

  assign do_start_counter = start_strobe;
  assign do_stop_counter = (stop_strobe) || 
                           (force_reload) || 
                           (counter_is_zero && ~control_continuous);

  always @(posedge clk or negedge reset_n) begin
    if (reset_n == 0)
        counter_is_running <= 1'b0;
    else if (clk_en) begin
        if (do_start_counter)
            counter_is_running <= 1;
        else if (do_stop_counter)
            counter_is_running <= 0;
    end
  end

  always @(posedge clk or negedge reset_n) begin
    if (reset_n == 0)
        delayed_unxcounter_is_zeroxx0 <= 0;
    else if (clk_en)
        delayed_unxcounter_is_zeroxx0 <= counter_is_zero;
  end

  assign timeout_event = (counter_is_zero) & ~(delayed_unxcounter_is_zeroxx0);

  always @(posedge clk or negedge reset_n) begin
    if (reset_n == 0)
        timeout_occurred <= 0;
    else if (clk_en) begin
        if (status_wr_strobe)
            timeout_occurred <= 0;
        else if (timeout_event)
            timeout_occurred <= 1;
    end
  end

  assign irq = timeout_occurred && control_interrupt_enable;

  assign read_mux_out = ({16{(address == 2)}} & period_l_register) |
                        ({16{(address == 3)}} & period_h_register) |
                        ({16{(address == 4)}} & snap_read_value[15 : 0]) |
                        ({16{(address == 5)}} & snap_read_value[31 : 16]) |
                        ({16{(address == 1)}} & control_register) |
                        ({16{(address == 0)}} & {counter_is_running, timeout_occurred});

  always @(posedge clk or negedge reset_n) begin
    if (reset_n == 0)
        readdata <= 0;
    else if (clk_en)
        readdata <= read_mux_out;
  end

  assign period_l_wr_strobe = chipselect && ~write_n && (address == 2);
  assign period_h_wr_strobe = chipselect && ~write_n && (address == 3);

  always @(posedge clk or negedge reset_n) begin
    if (reset_n == 0)
        period_l_register <= 49;
    else if (period_l_wr_strobe)
        period_l_register <= writedata;
  end

  always @(posedge clk or negedge reset_n) begin
    if (reset_n == 0)
        period_h_register <= 0;
    else if (period_h_wr_strobe)
        period_h_register <= writedata;
  end

  assign snap_l_wr_strobe = chipselect && ~write_n && (address == 4);
  assign snap_h_wr_strobe = chipselect && ~write_n && (address == 5);
  assign snap_strobe = snap_l_wr_strobe || snap_h_wr_strobe;

  always @(posedge clk or negedge reset_n) begin
    if (reset_n == 0)
        counter_snapshot <= 0;
    else if (snap_strobe)
        counter_snapshot <= internal_counter;
  end

  assign snap_read_value = counter_snapshot;
  assign control_wr_strobe = chipselect && ~write_n && (address == 1);

  always @(posedge clk or negedge reset_n) begin
    if (reset_n == 0)
        control_register <= 0;
    else if (control_wr_strobe)
        control_register <= writedata[3 : 0];
  end

  assign stop_strobe = writedata[3] && control_wr_strobe;
  assign start_strobe = writedata[2] && control_wr_strobe;
  assign control_continuous = control_register[1];
  assign control_interrupt_enable = control_register[0];
  assign status_wr_strobe = chipselect && ~write_n && (address == 0);

endmodule

files.origen_146568.v:
module origen_146568 (
    input wire i_Clk,
    input wire i_RX_Serial,
    input wire [7:0] i_TX_Byte,
    input wire i_TX_Load,
    output reg [7:0] o_RX_Byte,
    output reg o_RX_Done,
    output wire o_TX_Active,
    output reg o_TX_Done,
    output wire o_TX_Serial
);

// Parameters
parameter CLKS_PER_BIT = 5208; // 50MHz / 9600 baud
parameter IDLE = 3'b000;
parameter START_BIT = 3'b001;
parameter DATA_BITS = 3'b010;
parameter STOP_BIT = 3'b011;
parameter CLEANUP = 3'b100;

// Internal signals
reg [2:0] r_RX_State = IDLE;
reg [2:0] r_TX_State = IDLE;
reg [12:0] r_RX_Clock_Count = 0;
reg [12:0] r_TX_Clock_Count = 0;
reg [2:0] r_RX_Bit_Index = 0;
reg [2:0] r_TX_Bit_Index = 0;
reg [7:0] r_RX_Byte = 0;
reg r_TX_Serial = 1'b1;
reg r_TX_Active = 1'b0;

// RX Logic
always @(posedge i_Clk) begin
    case (r_RX_State)
        IDLE: begin
            o_RX_Done <= 1'b0;
            r_RX_Clock_Count <= 0;
            r_RX_Bit_Index <= 0;
            if (i_RX_Serial == 1'b0)
                r_RX_State <= START_BIT;
            else
                r_RX_State <= IDLE;
        end

        START_BIT: begin
            if (r_RX_Clock_Count == (CLKS_PER_BIT-1)/2) begin
                if (i_RX_Serial == 1'b0) begin
                    r_RX_Clock_Count <= 0;
                    r_RX_State <= DATA_BITS;
                end else
                    r_RX_State <= IDLE;
            end else begin
                r_RX_Clock_Count <= r_RX_Clock_Count + 1;
                r_RX_State <= START_BIT;
            end
        end

        DATA_BITS: begin
            if (r_RX_Clock_Count < CLKS_PER_BIT-1) begin
                r_RX_Clock_Count <= r_RX_Clock_Count + 1;
                r_RX_State <= DATA_BITS;
            end else begin
                r_RX_Clock_Count <= 0;
                r_RX_Byte[r_RX_Bit_Index] <= i_RX_Serial;
                if (r_RX_Bit_Index < 7) begin
                    r_RX_Bit_Index <= r_RX_Bit_Index + 1;
                    r_RX_State <= DATA_BITS;
                end else begin
                    r_RX_Bit_Index <= 0;
                    r_RX_State <= STOP_BIT;
                end
            end
        end

        STOP_BIT: begin
            if (r_RX_Clock_Count < CLKS_PER_BIT-1) begin
                r_RX_Clock_Count <= r_RX_Clock_Count + 1;
                r_RX_State <= STOP_BIT;
            end else begin
                o_RX_Done <= 1'b1;
                o_RX_Byte <= r_RX_Byte;
                r_RX_Clock_Count <= 0;
                r_RX_State <= CLEANUP;
            end
        end

        CLEANUP: begin
            r_RX_State <= IDLE;
            o_RX_Done <= 1'b0;
        end

        default: r_RX_State <= IDLE;
    endcase
end

// TX Logic
always @(posedge i_Clk) begin
    case (r_TX_State)
        IDLE: begin
            o_TX_Done <= 1'b0;
            r_TX_Serial <= 1'b1;
            r_TX_Clock_Count <= 0;
            r_TX_Bit_Index <= 0;
            if (i_TX_Load) begin
                r_TX_Active <= 1'b1;
                r_TX_State <= START_BIT;
            end else
                r_TX_State <= IDLE;
        end

        START_BIT: begin
            r_TX_Serial <= 1'b0;
            if (r_TX_Clock_Count < CLKS_PER_BIT-1) begin
                r_TX_Clock_Count <= r_TX_Clock_Count + 1;
                r_TX_State <= START_BIT;
            end else begin
                r_TX_Clock_Count <= 0;
                r_TX_State <= DATA_BITS;
            end
        end

        DATA_BITS: begin
            r_TX_Serial <= i_TX_Byte[r_TX_Bit_Index];
            if (r_TX_Clock_Count < CLKS_PER_BIT-1) begin
                r_TX_Clock_Count <= r_TX_Clock_Count + 1;
                r_TX_State <= DATA_BITS;
            end else begin
                r_TX_Clock_Count <= 0;
                if (r_TX_Bit_Index < 7) begin
                    r_TX_Bit_Index <= r_TX_Bit_Index + 1;
                    r_TX_State <= DATA_BITS;
                end else begin
                    r_TX_Bit_Index <= 0;
                    r_TX_State <= STOP_BIT;
                end
            end
        end

        STOP_BIT: begin
            r_TX_Serial <= 1'b1;
            if (r_TX_Clock_Count < CLKS_PER_BIT-1) begin
                r_TX_Clock_Count <= r_TX_Clock_Count + 1;
                r_TX_State <= STOP_BIT;
            end else begin
                o_TX_Done <= 1'b1;
                r_TX_Clock_Count <= 0;
                r_TX_State <= CLEANUP;
                r_TX_Active <= 1'b0;
            end
        end

        CLEANUP: begin
            o_TX_Done <= 1'b0;
            r_TX_State <= IDLE;
        end

        default: r_TX_State <= IDLE;
    endcase
end

assign o_TX_Active = r_TX_Active;
assign o_TX_Serial = r_TX_Serial;

endmodule

files.conformal_rtl_origen_146568.do:
// Conformal LEC RTL vs RTL: combinational equivalence (no netlist, no technology library).
// Golden and revised in ./rtl/golden.v, ./rtl/revised.v.
// Uses -SystemVerilog for SV support (logic, always_comb, int, $bits, etc); backward compatible with Verilog.
// NOTE: Conformal uses // for comments. Do NOT use # (Conformal treats # as a command and aborts).

set undefined cell black_box
read design ./rtl/golden.v -SystemVerilog -Golden
read design ./rtl/revised.v -SystemVerilog -Revised

// Switch to LEC mode and compare
set system mode lec
add compared points -all
compare
exit -force

files.rtlpp_02324.v:
module rtlpp_02324(
  input        rfsh_b,
  inout        adr15,
  inout        adr15_aux,
  input        adr14,
  input        adr8,
  input        iorq_b,
  input        mreq_b,
  input        reset_b,
  inout        wr_b,
  inout        rd_b,
  input [7:0]  data,
  input        ready,
  input        clk,
  input        m1_b,
  input [1:0]  dip,
  input        ramrd_b,
  inout        ramdis,
  output       ramcs_b,
  output [4:0] ramadrhi,
  output       ramoe_b,
  output       ramwe_b
);

  reg [5:0]        ramblock_q;
  reg [4:0]        ramadrhi_r;
  reg              cardsel_q;
  reg              mode3_q;
  reg              mwr_cyc_q;
  reg              mwr_cyc_f_q;
  reg              ramcs_b_r;
  reg              adr15_q;
  reg              exp_ram_r;
  reg              mreq_b_q;
  reg              reset_b_q;
  reg              reset1_b_q;
  reg              exp_ram_q;
  reg 	           urom_disable_q;
  reg 	           lrom_disable_q;
  reg              int_ramrd_r ;    

  wire             ram_ctrl_select_w;
  wire             rom_ctrl_select_w;
  wire [2:0]       shadow_bank;
  wire             full_shadow;
  wire             overdrive_mode;
  wire             mwr_cyc_d;
  wire             adr15_overdrive_w;
  wire             low512kb_mode;
  wire             reset_b_w;

  assign overdrive_mode= dip[0] | dip[1];
  assign shadow_mode   = dip[0];
  assign full_shadow   = dip[0]&dip[1];
  assign shadow_bank   = 3'b011;
  assign low512kb_mode = 1'b0 ;
  assign ramadrhi      = ramadrhi_r[4:0];

  assign ram_ctrl_select_w = (!iorq_b && !wr_b && !adr15 && data[6] && data[7] );
  assign rom_ctrl_select_w = (!iorq_b && !wr_b && !adr15 && !data[6] && data[7] );
  assign reset_b_w = reset1_b_q & reset_b & reset_b_q;

  always @ ( * ) begin
    int_ramrd_r = 1'b0 ; 	 
    if ( rfsh_b & !mreq_b )
      if ( (adr15_q|adr15_overdrive_w) != adr14 )
        int_ramrd_r = 1'b1; 
      else if ( urom_disable_q & ( {(adr15_q|adr15_overdrive_w),adr14} == 2'b11 ))
        int_ramrd_r = 1'b1; 
      else if ( lrom_disable_q & ( {(adr15_q|adr15_overdrive_w),adr14} == 2'b00 ))
        int_ramrd_r = 1'b1; 
  end

  assign ramwe_b = ! ( !wr_b & mwr_cyc_q & mwr_cyc_f_q );
  assign ramoe_b = (!int_ramrd_r) | rd_b ;

  assign wr_b = ( overdrive_mode & exp_ram_q & (mwr_cyc_q & !mwr_cyc_f_q)) ? 1'b0 : 1'bz;
  assign rd_b = ( overdrive_mode & exp_ram_q & (mwr_cyc_q|mwr_cyc_f_q)) ? 1'b0 : 1'bz ;

  assign mwr_cyc_d = !mreq_b & rd_b;
  assign adr15_overdrive_w = overdrive_mode & mode3_q & adr14 & ((shadow_mode) ? (mwr_cyc_q|mwr_cyc_d): !mreq_b) ;
  assign { adr15, adr15_aux} = (adr15_overdrive_w  ) ? 2'b11 : 2'bzz;

  assign ramdis = (full_shadow) ? 1'b1 :  (((!ramcs_b_r) & cardsel_q) ? 1'b1 : 1'bz);
  assign ramcs_b = !( ((!ramcs_b_r) & cardsel_q) | full_shadow) | mreq_b | !rfsh_b ;

  always @ (posedge clk)
    if ( mwr_cyc_d )
      mwr_cyc_q <= 1'b1;
    else if (mreq_b)
      mwr_cyc_q <= 1'b0;

  always @ (negedge clk or negedge reset_b_w)
    if ( !reset_b_w )
      mwr_cyc_f_q <= 1'b0;
    else
      mwr_cyc_f_q <= mwr_cyc_q;

  always @ (posedge clk or negedge reset_b_w)
     if ( !reset_b_w ) begin
      mreq_b_q = 1'b1;
      exp_ram_q = 1'b0;
    end
    else begin
      mreq_b_q = mreq_b;
       exp_ram_q = exp_ram_r;
    end

   always @ (posedge clk or negedge reset_b)
     if ( !reset_b )
       {reset1_b_q, reset_b_q}  = 2'b00;
     else
       {reset1_b_q, reset_b_q}  = {reset_b_q, reset_b};

  always @ (negedge clk or negedge reset_b_w )
    if ( !reset_b_w )
      adr15_q <= 1'b0;
    else
      adr15_q <= (mreq_b) ? adr15 : adr15_q;

  always @ (negedge clk or negedge reset_b_w)
    if (!reset_b_w) begin
      ramblock_q <= 6'b0;
      mode3_q <= 1'b0;
      cardsel_q <= 1'b0;
      urom_disable_q <= 1'b0;
      lrom_disable_q <= 1'b0;
    end
    else begin
       if ( ram_ctrl_select_w ) begin
          if ( shadow_mode && (data[5:3]==shadow_bank) )
            ramblock_q <= {data[5:4],1'b0, data[2:0]};
          else
            ramblock_q <= data[5:0] ;

          cardsel_q <= (low512kb_mode) ? !adr8 : adr8;
          mode3_q <= (data[2:0] == 3'b011);
       end
       else if ( rom_ctrl_select_w ) begin
          { urom_disable_q, lrom_disable_q } <= data[3:2];
       end
    end

  always @ ( * ) begin
    if ( shadow_mode )      
      case (ramblock_q[2:0])
 	3'b000: {exp_ram_r, ramcs_b_r, ramadrhi_r} = { 1'b0, !mwr_cyc_q , shadow_bank, adr15,adr14 };
 	3'b001: {exp_ram_r, ramcs_b_r, ramadrhi_r} = ( {adr15,adr14}==2'b11 ) ? {2'b10, ramblock_q[5:3],2'b11} : { 1'b0, !mwr_cyc_q , shadow_bank, adr15,adr14 };
 	3'b010: {exp_ram_r, ramcs_b_r, ramadrhi_r} = { 2'b10, ramblock_q[5:3], adr15,adr14} ;
 	3'b011: {exp_ram_r, ramcs_b_r, ramadrhi_r} = ( {adr15_q,adr14}==2'b11 ) ? {2'b10,ramblock_q[5:3],2'b11} : ({adr15_q,adr14}==2'b01) ? {2'b00,shadow_bank,2'b11} : { 1'b0, !mwr_cyc_q , shadow_bank, adr15,adr14 };
 	3'b100: {exp_ram_r, ramcs_b_r, ramadrhi_r} = ( {adr15,adr14}==2'b01 ) ? {2'b10,ramblock_q[5:3],2'b00} : { 1'b0, !mwr_cyc_q , shadow_bank, adr15, adr14 };
 	3'b101: {exp_ram_r, ramcs_b_r, ramadrhi_r} = ( {adr15,adr14}==2'b01 ) ? {2'b10,ramblock_q[5:3],2'b01} : { 1'b0, !mwr_cyc_q , shadow_bank, adr15, adr14 };
 	3'b110: {exp_ram_r, ramcs_b_r, ramadrhi_r} = ( {adr15,adr14}==2'b01 ) ? {2'b10,ramblock_q[5:3],2'b10} : { 1'b0, !mwr_cyc_q , shadow_bank, adr15, adr14 };
 	3'b111: {exp_ram_r, ramcs_b_r, ramadrhi_r} = ( {adr15,adr14}==2'b01 ) ? {2'b10,ramblock_q[5:3],2'b11} : { 1'b0, !mwr_cyc_q , shadow_bank, adr15, adr14 };
      endcase
    else
      case (ramblock_q[2:0])
 	3'b000: {exp_ram_r, ramcs_b_r, ramadrhi_r} = { 2'b01, 5'bxxxxx };
 	3'b001: {exp_ram_r, ramcs_b_r, ramadrhi_r} = ( {adr15,adr14}==2'b11 ) ? {2'b10,ramblock_q[5:3],2'b11} : {2'b01, 5'bxxxxx};
 	3'b010: {exp_ram_r, ramcs_b_r, ramadrhi_r} = { 2'b10,ramblock_q[5:3],adr15,adr14} ;
 	3'b011: {exp_ram_r, ramcs_b_r, ramadrhi_r} = ( {adr15_q,adr14}==2'b11 ) ? {2'b10,ramblock_q[5:3],2'b11} : {2'b01, 5'bxxxxx };
 	3'b100: {exp_ram_r, ramcs_b_r, ramadrhi_r} = ( {adr15,adr14}==2'b01 ) ? {2'b10,ramblock_q[5:3],2'b00} : {2'b01, 5'bxxxxx };
 	3'b101: {exp_ram_r, ramcs_b_r, ramadrhi_r} = ( {adr15,adr14}==2'b01 ) ? {2'b10,ramblock_q[5:3],2'b01} : {2'b01, 5'bxxxxx };
 	3'b110: {exp_ram_r, ramcs_b_r, ramadrhi_r} = ( {adr15,adr14}==2'b01 ) ? {2'b10,ramblock_q[5:3],2'b10} : {2'b01, 5'bxxxxx };
 	3'b111: {exp_ram_r, ramcs_b_r, ramadrhi_r} = ( {adr15,adr14}==2'b01 ) ? {2'b10,ramblock_q[5:3],2'b11} : {2'b01, 5'bxxxxx };
      endcase
  end

endmodule

