module autovcoder_121511 (
    input  wire       clk,    //50M
    input  wire       rst_n,
    output reg        sclk,   //1M
    output wire       cs,
    output wire       din,
    input  wire [9:0] datain
);

  parameter D_N = 50 - 1;
  reg [5:0] div_cnt;
  reg [3:0] shift_cnt;

  reg shift_en;
  reg shift_flag;
  reg shift_end;

  reg [9:0] shift_buf;


  always @(posedge clk or negedge rst_n) begin
    if (rst_n == 1'b0) div_cnt <= 6'd0;
    else if (div_cnt == D_N) div_cnt <= 6'd0;
    else div_cnt <= div_cnt + 6'd1;
  end

  always @(posedge clk or negedge rst_n) begin
    if (rst_n == 1'b0) shift_flag <= 1'b0;
    else if ((div_cnt == D_N) && (shift_end == 1'b0)) shift_flag <= 1'b1;
    else shift_flag <= 1'b0;
  end

  always @(posedge clk or negedge rst_n) begin
    if (rst_n == 1'b0) shift_cnt <= 4'b0000;
    else if (shift_flag == 1'b1) shift_cnt <= shift_cnt + 4'b0001;
    else shift_cnt <= shift_cnt;
  end

  always @(posedge clk or negedge rst_n) begin
    if (rst_n == 1'b0) shift_en <= 1'b0;
    else if ((shift_cnt == 4'b1001) && (shift_flag == 1'b1)) shift_en <= 1'b0;
    else if (shift_cnt == 4'b0000) shift_en <= 1'b1;
  end

  always @(posedge clk or negedge rst_n) begin
    if (rst_n == 1'b0) shift_buf <= 10'd0;
    else if ((shift_flag == 1'b1) && (shift_en == 1'b1)) shift_buf <= {shift_buf[8:0], 1'b0};
    else if ((shift_cnt == 4'b0000) && (shift_en == 1'b1)) shift_buf <= datain;
  end

  assign din = shift_buf[9];
  assign cs  = ~shift_en;

  always @(posedge clk or negedge rst_n) begin
    if (rst_n == 1'b0) sclk <= 1'b1;
    else if ((shift_en == 1'b1) && (div_cnt == 6'd2)) sclk <= 1'b0;
    else if ((shift_en == 1'b1) && (div_cnt == 6'd27)) sclk <= 1'b1;

  end

endmodule

files.origen_062320.v:
module origen_062320(
    input CLK,
    input RESET,
    input BTNL,
    input BTNT,
    input BTNR,
    input BTND,
    input [3:0] SCORE,
    output [1:0] STATE_OUT
);

    reg [1:0] Curr_state, Next_state;

    // State definitions
    localparam INITIAL = 2'b00;
    localparam GAME_IN_PROGRESS = 2'b01;
    localparam GAME_OVER = 2'b10;

    // State register
    always @(posedge CLK or posedge RESET) begin
        if (RESET)
            Curr_state <= INITIAL;
        else
            Curr_state <= Next_state;
    end

    // Next state logic
    always @(*) begin
        case (Curr_state)
            INITIAL: begin
                if (BTNL | BTNT | BTNR | BTND)
                    Next_state = GAME_IN_PROGRESS;
                else
                    Next_state = INITIAL;
            end
            GAME_IN_PROGRESS: begin
                if (SCORE == 4'b0011)
                    Next_state = GAME_OVER;
                else
                    Next_state = GAME_IN_PROGRESS;
            end
            GAME_OVER: begin
                Next_state = GAME_OVER;
            end
            default: begin
                Next_state = INITIAL;
            end
        endcase
    end

    // Output logic
    assign STATE_OUT = Curr_state;

endmodule

