module autovcoder_130958 (
    input wire clk,
    input wire reset,
    input wire [7:0] data_in,
    input wire transmit_enable,
    output reg tx,
    output reg transmission_complete
);
    parameter BAUD_RATE = 9600; // Fixed baud rate
    parameter CLOCK_FREQ = 50000000; // Example clock frequency
    localparam BIT_PERIOD = CLOCK_FREQ / BAUD_RATE;

    reg [3:0] bit_index;
    reg [15:0] counter;
    reg transmitting;

    always @(posedge clk or posedge reset) begin
        if (reset) begin
            tx <= 1; // Idle state for TX is high
            transmission_complete <= 0;
            bit_index <= 0;
            counter <= 0;
            transmitting <= 0;
        end else begin
            if (transmit_enable && !transmitting) begin
                transmitting <= 1;
                tx <= 0; // Start bit
                bit_index <= 0;
                counter <= 0;
                transmission_complete <= 0;
            end

            if (transmitting) begin
                if (counter < BIT_PERIOD - 1) begin
                    counter <= counter + 1;
                end else begin
                    counter <= 0;
                    if (bit_index < 8) begin
                        tx <= data_in[bit_index]; // Send data bits
                        bit_index <= bit_index + 1;
                    end else if (bit_index == 8) begin
                        tx <= 1; // Stop bit
                        bit_index <= bit_index + 1;
                    end else begin
                        transmitting <= 0; // Transmission complete
                        transmission_complete <= 1;
                    end
                end
            end
        end
    end
endmodule

files.origen_215703.v:
module origen_215703(
    input clk,
    input reset,
    input [1:0] control,
    output reg warnbit,
    output reg [3:0] curr_state
);

parameter state_0 = 4'b0000, state_1 = 4'b0001, state_2 = 4'b0010, state_3 = 4'b0011,
          state_4 = 4'b0100, state_5 = 4'b0101, state_6 = 4'b0110, state_7 = 4'b0111;

always @(posedge clk or posedge reset) begin
    if (reset) begin
        curr_state <= state_0;
        warnbit <= 1'b0;
    end
    else begin
        case (control)
            2'b00: curr_state <= curr_state; // same_state_ctrl
            2'b01: begin // counter_clk_wise_ctrl
                case (curr_state)
                    state_0: curr_state <= state_7;
                    state_7: curr_state <= state_6;
                    state_6: curr_state <= state_5;
                    state_5: curr_state <= state_4;
                    state_4: curr_state <= state_3;
                    state_3: curr_state <= state_2;
                    state_2: curr_state <= state_1;
                    state_1: curr_state <= state_0;
                endcase
            end
            2'b10: begin // clk_wise_ctrl
                case (curr_state)
                    state_0: curr_state <= state_1;
                    state_1: curr_state <= state_2;
                    state_2: curr_state <= state_3;
                    state_3: curr_state <= state_4;
                    state_4: curr_state <= state_5;
                    state_5: curr_state <= state_6;
                    state_6: curr_state <= state_7;
                    state_7: curr_state <= state_0;
                endcase
            end
            2'b11: begin // warn_state_ctrl
                warnbit <= 1'b1;
                curr_state <= curr_state;
            end
        endcase
    end
end

endmodule

files.origen_001905.v:
module origen_001905 (
    input wire CLK,
    input wire PCLK_EN,
    output reg [8:0] HPOS,
    output reg [8:0] VPOS,
    output reg HBLK,
    output reg VBLK,
    output reg HSYN,
    output reg VSYN
);

    reg [8:0] hcnt;
    reg [8:0] vcnt;

    // Horizontal counter
    always @(posedge CLK) begin
        if (PCLK_EN) begin
            if (hcnt == 9'd383) begin
                hcnt <= 9'd0;
            end else begin
                hcnt <= hcnt + 1'b1;
            end
        end
    end

    // Vertical counter
    always @(posedge CLK) begin
        if (PCLK_EN && hcnt == 9'd383) begin
            if (vcnt == 9'd242) begin
                vcnt <= 9'd0;
            end else begin
                vcnt <= vcnt + 1'b1;
            end
        end
    end

    // Horizontal timing
    always @(posedge CLK) begin
        if (PCLK_EN) begin
            HPOS <= hcnt;
            HBLK <= (hcnt >= 9'd291) || (hcnt < 9'd1);
            HSYN <= ~((hcnt >= 9'd300) && (hcnt < 9'd324));
        end
    end

    // Vertical timing
    always @(posedge CLK) begin
        if (PCLK_EN && hcnt == 9'd383) begin
            VPOS <= vcnt;
            VBLK <= (vcnt >= 9'd223) && (vcnt < 9'd242);
            VSYN <= ~((vcnt >= 9'd228) && (vcnt < 9'd235));
        end
    end

endmodule

