module origen_058674 (
    input wire Clock,
    input wire [3:0] Difficulty,
    output reg DisplayClock,
    output reg GameClock,
    output reg ScoreDisplayClock
);

    // Parameters for clock division
    parameter displayFlipTime = 1;
    parameter gameClockFlipTime = 500000;
    parameter scoreDisplayFlipTime = 250000;

    // Internal counters
    reg [31:0] displayCtr;
    reg [31:0] gameCtr;
    reg [31:0] scoreDisplayCtr;

    // Clock generation logic
    always @(posedge Clock) begin
        // DisplayClock generation
        if (displayCtr == displayFlipTime - 1) begin
            DisplayClock <= ~DisplayClock;
            displayCtr <= 0;
        end else begin
            displayCtr <= displayCtr + 1;
        end

        // GameClock generation
        if (gameCtr >= gameClockFlipTime - 1) begin
            GameClock <= ~GameClock;
            gameCtr <= 0;
        end else begin
            gameCtr <= gameCtr + Difficulty;
        end

        // ScoreDisplayClock generation
        if (scoreDisplayCtr == scoreDisplayFlipTime - 1) begin
            ScoreDisplayClock <= ~ScoreDisplayClock;
            scoreDisplayCtr <= 0;
        end else begin
            scoreDisplayCtr <= scoreDisplayCtr + 1;
        end
    end

    // Initial values
    initial begin
        DisplayClock = 0;
        GameClock = 0;
        ScoreDisplayClock = 0;
        displayCtr = 0;
        gameCtr = 0;
        scoreDisplayCtr = 0;
    end

endmodule

files.origen_145425.v:
module origen_145425 (
    input wire clk,
    input wire rst_n,
    input wire [4:0] BIN,
    output reg [3:0] BCD0,
    output reg [3:0] BCD1
);

    reg [4:0] bin_reg1, bin_reg2;
    reg [7:0] bcd_reg1, bcd_reg2;

    // Stage 1: Input registration and initial shift
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            bin_reg1 <= 5'b0;
            bcd_reg1 <= 8'b0;
        end else begin
            bin_reg1 <= BIN;
            bcd_reg1 <= {3'b0, BIN};
        end
    end

    // Stage 2: Double dabble algorithm
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            bin_reg2 <= 5'b0;
            bcd_reg2 <= 8'b0;
        end else begin
            bin_reg2 <= bin_reg1;

            // Check if ones digit is 5 or greater
            if (bcd_reg1[3:0] >= 5)
                bcd_reg2[3:0] <= bcd_reg1[3:0] + 3;
            else
                bcd_reg2[3:0] <= bcd_reg1[3:0];

            // Check if tens digit is 5 or greater
            if (bcd_reg1[7:4] >= 5)
                bcd_reg2[7:4] <= bcd_reg1[7:4] + 3;
            else
                bcd_reg2[7:4] <= bcd_reg1[7:4];
        end
    end

    // Stage 3: Final shift and output
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            BCD0 <= 4'b0;
            BCD1 <= 4'b0;
        end else begin
            BCD0 <= bcd_reg2[3:0];
            BCD1 <= bcd_reg2[7:4];
        end
    end

endmodule

files.origen_191567.v:
module origen_191567(
    input  wire req24, req23, req22, req21, req20,
    input  wire clk, rst,
    output reg  gnt24, gnt23, gnt22, gnt21, gnt20
);

    // State definitions
    localparam IDLE = 3'b000, GNT0 = 3'b001, GNT1 = 3'b010, GNT2 = 3'b011, GNT3 = 3'b100, GNT4 = 3'b101;

    // State register
    reg [2:0] state, next_state;

    // Next state logic
    always @(*) begin
        case (state)
            IDLE: begin
                if (req20) next_state = GNT0;
                else if (req21) next_state = GNT1;
                else if (req22) next_state = GNT2;
                else if (req23) next_state = GNT3;
                else if (req24) next_state = GNT4;
                else next_state = IDLE;
            end
            GNT0: next_state = req20 ? GNT0 : IDLE;
            GNT1: next_state = req21 ? GNT1 : IDLE;
            GNT2: next_state = req22 ? GNT2 : IDLE;
            GNT3: next_state = req23 ? GNT3 : IDLE;
            GNT4: next_state = req24 ? GNT4 : IDLE;
            default: next_state = IDLE;
        endcase
    end

    // State register update
    always @(posedge clk or posedge rst) begin
        if (rst) state <= IDLE;
        else state <= next_state;
    end

    // Output logic
    always @(*) begin
        gnt20 = 1'b0;
        gnt21 = 1'b0;
        gnt22 = 1'b0;
        gnt23 = 1'b0;
        gnt24 = 1'b0;

        case (state)
            GNT0: gnt20 = 1'b1;
            GNT1: gnt21 = 1'b1;
            GNT2: gnt22 = 1'b1;
            GNT3: gnt23 = 1'b1;
            GNT4: gnt24 = 1'b1;
        endcase
    end

endmodule

