module origen_097048 #(
    parameter APB_HWCE_ADDR_WIDTH = 32
) (
    input  wire                           clk_i,
    input  wire                           rst_ni,
    output reg  [31:0]                    apb_hwce_prdata_o,
    output wire                           apb_hwce_ready_o,
    output wire                           apb_hwce_pslverr_o,
    input  wire [APB_HWCE_ADDR_WIDTH-1:0] apb_hwce_addr_i,
    input  wire                           apb_hwce_enable_i,
    input  wire                           apb_hwce_psel_i,
    input  wire [31:0]                    apb_hwce_pwdata_i,
    input  wire                           apb_hwce_pwrite_i
);

    wire s_is_apb_write;
    wire s_is_apb_read;
    reg [1:0] do_display;

    assign s_is_apb_write = apb_hwce_psel_i && apb_hwce_enable_i && apb_hwce_pwrite_i;
    assign s_is_apb_read  = apb_hwce_psel_i && apb_hwce_enable_i && !apb_hwce_pwrite_i;

    assign apb_hwce_ready_o = 1'b1;
    assign apb_hwce_pslverr_o = 1'b0;

    always @(posedge clk_i or negedge rst_ni) begin
        if (!rst_ni) begin
            do_display <= 2'b00;
        end else begin
            if (s_is_apb_write) begin
                do_display <= 2'b01;
            end else if (s_is_apb_read) begin
                do_display <= 2'b10;
            end else begin
                do_display <= 2'b00;
            end
        end
    end

    always @(posedge clk_i) begin
        if (do_display == 2'b01) begin
            $display("APB WRITE: addr %x, data %x", apb_hwce_addr_i, apb_hwce_pwdata_i);
        end else if (do_display == 2'b10) begin
            $display("APB READ: addr %x", apb_hwce_addr_i);
        end
    end

    always @(posedge clk_i or negedge rst_ni) begin
        if (!rst_ni) begin
            apb_hwce_prdata_o <= 32'h0;
        end else if (s_is_apb_read) begin
            apb_hwce_prdata_o <= 32'h00DA41DE;
        end
    end

endmodule

files.origen_053154.v:
module origen_053154 #(
    parameter TX_DATA_WIDTH = 64
) (
    input [TX_DATA_WIDTH-1:0] data_in_rx_uns,
    input [TX_DATA_WIDTH-1:0] data_in,
    input enable,
    input [1:0] sync_info,
    input clk,
    input rst,
    input blocksync_out,
    input valid_frame,
    input [57:0] ber_poly,
    output reg [TX_DATA_WIDTH+1:0] data_out,
    output reg ber_sync,
    output reg sync_init
);

    reg [57:0] scrambler;
    reg [TX_DATA_WIDTH-1:0] tempData;
    wire [57:0] poly;
    wire xorBit;

    assign poly = {scrambler[56:0], xorBit};
    assign xorBit = scrambler[57] ^ scrambler[38] ^ data_in[TX_DATA_WIDTH-1];

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            scrambler <= {58{1'b1}};
            ber_sync <= 1'b0;
            sync_init <= 1'b0;
        end else if (enable) begin
            if (valid_frame && blocksync_out) begin
                if (!ber_sync) begin
                    scrambler <= scrambler ^ ber_poly;
                    ber_sync <= 1'b1;
                    sync_init <= 1'b1;
                end else begin
                    scrambler <= poly;
                end
            end else begin
                ber_sync <= 1'b0;
                sync_init <= 1'b0;
            end
        end
    end

    always @(posedge clk) begin
        if (enable) begin
            tempData <= {xorBit, tempData[TX_DATA_WIDTH-1:1]};
            data_out <= {tempData ^ data_in, sync_info};
        end
    end

endmodule

files.autovcoder_059451.v:
module autovcoder_059451 #(
    parameter C_DWIDTH     = 1,  //  Allowed values: 1+
    parameter C_INV_EXISTS = 0   //  Allowed values: 0,1
) (
    // system signals
    input  wire                Clk,
    input  wire                Rst,
    // FIFO side signals
    input  wire                FIFO_Exists,  // Exists or Empty
    output wire                FIFO_Read,    // Read is Pop
    input  wire [C_DWIDTH-1:0] FIFO_Data,
    // Pipelined signals
    output wire                PIPE_Exists,
    input  wire                PIPE_Read,
    output reg  [C_DWIDTH-1:0] PIPE_Data
);

  wire fifo_exists_i;
  reg  fifo_exists_d1;
  wire fifo_exists_rising_edge;
  wire fifo_read_cond_1;
  wire fifo_read_cond_2;
  reg  pipe_exists_i;

  // Exists is really an empty signal in this case
  generate
    if (C_INV_EXISTS) begin : FIFO_EMPTY
      assign fifo_exists_i = ~FIFO_Exists;
      assign PIPE_Exists   = ~pipe_exists_i;
    end else begin : FIFO_EXISTS
      assign fifo_exists_i = FIFO_Exists;
      assign PIPE_Exists   = pipe_exists_i;
    end
  endgenerate

  // Exists signal is a S/R latch w/ rst
  always @(posedge Clk)
    if (Rst) pipe_exists_i <= 1'b0;
    else pipe_exists_i <= fifo_exists_i | (~PIPE_Read & pipe_exists_i);

  // Rising edge detector for FIFO_Exists
  always @(posedge Clk) fifo_exists_d1 <= fifo_exists_i;

  assign fifo_exists_rising_edge = fifo_exists_i & ~fifo_exists_d1;

  // Condition 1 to Read the FIFO our pipe is empty and the fifo is not
  assign fifo_read_cond_1 = ~pipe_exists_i & fifo_exists_rising_edge;

  // condition 2 to read the FIFO is if a READ is issued and we have more data
  // in the fifo
  assign fifo_read_cond_2 = PIPE_Read & fifo_exists_i;

  // Or the two conditions
  assign FIFO_Read = fifo_read_cond_1 | fifo_read_cond_2;

  // Data pipeline register, we advance every time a read is performed
  always @(posedge Clk) if (FIFO_Read) PIPE_Data <= FIFO_Data;



endmodule

files.origen_080453.v:
module origen_080453(
    input wire alarme,
    input wire dia_util,
    input wire clock,
    input wire reset,
    output reg desligar
);

    // State encoding
    localparam DORMINDO = 2'b00;
    localparam ACORDADO = 2'b01;
    localparam LEVANTADO = 2'b10;

    reg [1:0] state, next_state;

    // State register
    always @(posedge clock or posedge reset) begin
        if (reset)
            state <= DORMINDO;
        else
            state <= next_state;
    end

    // Next state logic
    always @(*) begin
        next_state = state; // Default: stay in current state
        case (state)
            DORMINDO: begin
                if (alarme)
                    next_state = ACORDADO;
            end
            ACORDADO: begin
                if (dia_util)
                    next_state = LEVANTADO;
                else
                    next_state = DORMINDO;
            end
            LEVANTADO: begin
                // No transitions defined for LEVANTADO state
            end
            default: next_state = DORMINDO;
        endcase
    end

    // Output logic
    always @(posedge clock or posedge reset) begin
        if (reset)
            desligar <= 1'b0;
        else if (state == ACORDADO)
            desligar <= 1'b1;
        else
            desligar <= 1'b0;
    end

endmodule

