module origen_016071 (
    input wire clk,
    input wire Dir,
    input wire StepEnable,
    input wire rst,
    input wire [3:0] speed,
    output reg [3:0] StepDrive
);

    reg [2:0] state;
    reg [15:0] StepCounter;
    reg [15:0] StepLockOut;

    always @(posedge clk or negedge rst) begin
        if (!rst) begin
            StepDrive <= 4'b0000;
            state <= 3'b000;
            StepCounter <= 16'd0;
        end else begin
            StepCounter <= StepCounter + 1;

            case (speed)
                4'd0: StepLockOut <= 16'd65535;
                4'd1: StepLockOut <= 16'd32767;
                4'd2: StepLockOut <= 16'd16383;
                4'd3: StepLockOut <= 16'd8191;
                4'd4: StepLockOut <= 16'd4095;
                4'd5: StepLockOut <= 16'd2047;
                4'd6: StepLockOut <= 16'd1023;
                4'd7: StepLockOut <= 16'd511;
                4'd8: StepLockOut <= 16'd255;
                default: StepLockOut <= 16'd1023;
            endcase

            if (StepEnable && (StepCounter >= StepLockOut)) begin
                StepCounter <= 16'd0;
                if (Dir)
                    state <= state + 1;
                else
                    state <= state - 1;
            end

            case (state)
                3'b000: StepDrive <= 4'b1000;
                3'b001: StepDrive <= 4'b1100;
                3'b010: StepDrive <= 4'b0100;
                3'b011: StepDrive <= 4'b0110;
                3'b100: StepDrive <= 4'b0010;
                3'b101: StepDrive <= 4'b0011;
                3'b110: StepDrive <= 4'b0001;
                3'b111: StepDrive <= 4'b1001;
            endcase
        end
    end

endmodule

files.origen_096472.v:
module origen_096472 #(
    parameter DATA_WIDTH = 8,
    parameter CTR_WIDTH = 4
) (
    input wire clk,
    input wire rst,
    input wire ready,
    input wire [DATA_WIDTH-1:0] stream_in,
    output reg [DATA_WIDTH+CTR_WIDTH-1:0] compressed_stream,
    output reg valid
);

localparam CTR_MAX = (1 << CTR_WIDTH) - 1;

reg [DATA_WIDTH-1:0] stream_in_prev;
reg [CTR_WIDTH-1:0] seq_counter;
reg ready_prev;

always @(posedge clk or negedge rst) begin
    if (!rst) begin
        compressed_stream <= 0;
        valid <= 0;
        stream_in_prev <= 0;
        seq_counter <= 0;
        ready_prev <= 0;
    end else begin
        ready_prev <= ready;

        if (ready && ready_prev) begin
            if (stream_in == stream_in_prev) begin
                if (seq_counter < CTR_MAX) begin
                    seq_counter <= seq_counter + 1;
                    valid <= 0;
                end else begin
                    compressed_stream <= {seq_counter, stream_in_prev};
                    valid <= 1;
                    seq_counter <= 0;
                end
            end else begin
                if (seq_counter > 0) begin
                    compressed_stream <= {seq_counter, stream_in_prev};
                    valid <= 1;
                end else begin
                    valid <= 0;
                end
                seq_counter <= 0;
                stream_in_prev <= stream_in;
            end
        end else begin
            valid <= 0;
        end
    end
end

endmodule

files.origen_090148.v:
module origen_090148 (
    input wire clock,
    input wire reset,
    input wire [15:0] address_bus,
    inout wire [7:0] data_bus,
    input wire nread,
    input wire nwrite,
    input wire nsel
);

    reg [23:0] read_locations [0:255];
    reg [23:0] write_locations [0:255];
    reg [7:0] read_idx, write_idx;
    reg [15:0] read_addr, write_addr;
    reg [7:0] read_data, write_data;

    initial begin
        $readmemh("read_locations.mem", read_locations);
        $readmemh("write_locations.mem", write_locations);
        read_idx = 0;
        write_idx = 0;
    end

    always @(*) begin
        {read_addr, read_data} = read_locations[read_idx];
        {write_addr, write_data} = write_locations[write_idx];
    end

    assign data_bus = (!nread && !nsel) ? read_data : 8'bz;

    always @(posedge clock or negedge reset) begin
        if (!reset) begin
            read_idx <= 0;
            write_idx <= 0;
        end else begin
            if (!nread && !nsel) begin
                if (address_bus !== read_addr) begin
                    $display("Error: Read address mismatch at time %0t", $time);
                    $display("Expected: %h, Actual: %h", read_addr, address_bus);
                    $finish;
                end
                read_idx <= read_idx + 1;
            end

            if (!nwrite && !nsel) begin
                if (address_bus !== write_addr || data_bus !== write_data) begin
                    $display("Error: Write mismatch at time %0t", $time);
                    $display("Expected: Address %h, Data %h", write_addr, write_data);
                    $display("Actual: Address %h, Data %h", address_bus, data_bus);
                    $finish;
                end
                write_idx <= write_idx + 1;
            end
        end
    end

endmodule

files.origen_204408.v:
module origen_204408(
    input clk,
    input enable,
    output [7:0] dir,
    output reset,
    output WR,
    output RD,
    output ready
);

    reg [9:0] clkr;
    reg [2:0] next;
    reg [2:0] state;
    reg [7:0] dir_reg;
    reg reset_reg, WR_reg, RD_reg, ready_reg;

    always @(posedge clk) begin
        if (enable) begin
            if (state == 2'b00) begin
                dir_reg <= dir_reg + 1;
                next <= 2'b01;
            end
            else if (state == 2'b01) begin
                reset_reg <= 1;
                if (WR_reg == 0)
                    next <= 2'b10;
            end
            else if (state == 2'b10) begin
                WR_reg <= 0;
                if (dir_reg == 8'b00001010) begin
                    ready_reg <= 1;
                    dir_reg <= 8'b00000001;
                end
                else
                    next <= 2'b00;
            end

            if (clkr == 9'b100000001) begin
                reset_reg <= 0;
                WR_reg <= 0;
                clkr <= 0;
            end
            else
                clkr <= clkr + 1;

            state <= next;
        end
    end

    assign dir = dir_reg;
    assign reset = reset_reg;
    assign WR = WR_reg;
    assign RD = RD_reg;
    assign ready = ready_reg;

endmodule

files.autovcoder_017688.v:
module autovcoder_017688 #(
    parameter ADDR = 10,
    WIDTH = 8,
    WORDS = 1024,
    WRITETHRU = 0,
    DEFAULT = {WIDTH{1'b1}},
    INIT_FILE = "NONE",
    INSTANCE_NAME = "U1"
) (
    input  wire               clk,
    input  wire               cs,
    input  wire               rd,
    input  wire               wr,
    input  wire [ ADDR-1 : 0] addr,
    input  wire [WIDTH-1 : 0] wdata,
    output reg  [WIDTH-1 : 0] rdata
);
  // Memory Array
  reg [WIDTH-1:0] mem[0:WORDS-1];
  // If used as Rom then load a memory image at startup
  initial begin
    if (INIT_FILE == "NONE") begin
    end else begin
      $readmemh(INIT_FILE, mem);
    end
  end

  // Write function   
  always @(posedge clk) if (wr && cs) mem[addr[ADDR-1:0]] <= wdata[WIDTH-1:0];
  generate
    if (WRITETHRU) begin
      // Read function gets new data if also a write cycle
      // latch the read addr for next cycle   
      reg [ADDR-1:0] l_raddr;
      reg            l_cycle;

      always @(posedge clk) begin
        l_raddr <= addr;
        l_cycle <= rd && cs;
      end

      // Read into a wire and then pass to rdata because some synth tools can't handle a memory in a always block
      wire [WIDTH-1:0] tmp_rdata;
      assign tmp_rdata = (l_cycle) ? mem[{l_raddr[ADDR-1:0]}] : DEFAULT;
      always @(*) rdata = tmp_rdata;
    end else begin
      // Read function gets old data if also a write cycle
      always @(posedge clk)
        if (rd && cs) rdata <= mem[{addr[ADDR-1:0]}];
        else rdata <= DEFAULT;
    end
  endgenerate
endmodule

files.autovcoder_104135.v:
module autovcoder_104135 (
    input                clk,
    input                rst_n,
    input                in_valid,
    input  signed [23:0] din_r,
    input  signed [23:0] din_i,
    output signed [23:0] dout_r,
    output signed [23:0] dout_i
);
  ////////////////////////////////////////////
  // Internal signals
  reg [95:0] shift_reg_r;
  reg [95:0] shift_reg_i;
  reg [95:0] tmp_reg_r;
  reg [95:0] tmp_reg_i;
  reg [3:0] counter_4, next_counter_4;
  reg valid, next_valid;
  ////////////////////////////////////////////
  // Output logic
  assign dout_r = shift_reg_r[95:72];
  assign dout_i = shift_reg_i[95:72];
  ////////////////////////////////////////////
  // Next state logic
  always @(*) begin
    next_counter_4 = counter_4 + 3'd1;
    tmp_reg_r      = shift_reg_r;
    tmp_reg_i      = shift_reg_i;
    next_valid     = valid;
  end
  ////////////////////////////////////////////
  // State register
  always @(posedge clk or negedge rst_n) begin
    if (~rst_n) begin
      shift_reg_r <= 0;
      shift_reg_i <= 0;
      counter_4   <= 0;
      valid       <= 0;
    end else if (in_valid) begin
      counter_4   <= next_counter_4;
      shift_reg_r <= (tmp_reg_r << 24) + din_r;
      shift_reg_i <= (tmp_reg_i << 24) + din_i;
      valid       <= in_valid;
    end else if (valid) begin
      counter_4   <= next_counter_4;
      shift_reg_r <= (tmp_reg_r << 24) + din_r;
      shift_reg_i <= (tmp_reg_i << 24) + din_i;
      valid       <= next_valid;
    end
  end
endmodule

files.origen_135702.v:
module origen_135702 (
    input wire clk,
    input wire reset,
    input wire [3:0] in1,
    input wire [3:0] in2,
    input wire [1:0] op,
    output reg [3:0] out1,
    output reg [3:0] out2,
    output reg [3:0] out3,
    output reg [3:0] out4
);

reg [1:0] prev_op;

always @(posedge clk or posedge reset) begin
    if (reset) begin
        out1 <= 4'b0000;
        out2 <= 4'b0000;
        out3 <= 4'b0000;
        out4 <= 4'b0000;
        prev_op <= 2'b11; // Initialize to an invalid value
    end else if (op != prev_op) begin
        case (op)
            2'b00: begin // AND operation
                out1 <= in1[0] & in2[0];
                out2 <= in1[1] & in2[1];
                out3 <= in1[2] & in2[2];
                out4 <= in1[3] & in2[3];
            end
            2'b01: begin // OR operation
                out1 <= in1[0] | in2[0];
                out2 <= in1[1] | in2[1];
                out3 <= in1[2] | in2[2];
                out4 <= in1[3] | in2[3];
            end
            2'b10: begin // XOR operation
                out1 <= in1[0] ^ in2[0];
                out2 <= in1[1] ^ in2[1];
                out3 <= in1[2] ^ in2[2];
                out4 <= in1[3] ^ in2[3];
            end
            2'b11: begin // NOT operation
                out1 <= ~in1[0];
                out2 <= ~in1[1];
                out3 <= ~in1[2];
                out4 <= ~in1[3];
            end
        endcase
        prev_op <= op;
    end
end

endmodule

