  assign bus_A  = (ue[3] ? MAR : (ue[0] ? IP : 0));
  assign bus_RE = (ue[0] || (ue[3] && load));
  reg [31:0] R[7:0];
  assign Aop = R[Aad];
  assign Bop = R[Bad];
  assign bus_WE = (ue[3] && store);
  assign bus_out = MDRw;
  always @(posedge clk)
    if (rst) begin
      R[0] <= 0;
      R[1] <= 0;
      R[2] <= 0;
      R[3] <= 0;
      R[4] <= 0;
      R[5] <= 0;
      R[6] <= 0;
      R[7] <= 0;
    end else if (ue[4])
      if (((aluop || move) || load))
        if (load) R[RS] <= MDRr;
        else R[RD] <= C;
  assign current_opcode = opcode;
endmodule

