module origen_128646 (
    input wire clock,
    input wire reset,
    input wire s_tick,
    input wire tx_start,
    input wire [7:0] data_in,
    output reg tx,
    output reg tx_done,
    output reg baud_rate_clock
);

    // Parameters
    parameter CLOCK_FREQ = 50_000_000;
    parameter BAUD_RATE = 9600;
    parameter TICKS_PER_BIT = CLOCK_FREQ / (BAUD_RATE * 16);
    parameter DATA_BITS = 8;
    parameter TOTAL_BITS = 10; // Start bit + 8 data bits + Stop bit

    // State machine states
    localparam IDLE = 2'b00;
    localparam START = 2'b01;
    localparam DATA = 2'b10;
    localparam STOP = 2'b11;

    // Registers
    reg [1:0] state;
    reg [3:0] tick_counter;
    reg [3:0] bit_counter;
    reg [7:0] shift_reg;

    // Baud rate generator
    reg [15:0] baud_counter;

    always @(posedge clock or posedge reset) begin
        if (reset) begin
            baud_counter <= 0;
            baud_rate_clock <= 0;
        end else if (s_tick) begin
            if (baud_counter == TICKS_PER_BIT - 1) begin
                baud_counter <= 0;
                baud_rate_clock <= ~baud_rate_clock;
            end else begin
                baud_counter <= baud_counter + 1;
            end
        end
    end

    // UART transmitter state machine
    always @(posedge clock or posedge reset) begin
        if (reset) begin
            state <= IDLE;
            tx <= 1'b1;
            tx_done <= 1'b0;
            tick_counter <= 0;
            bit_counter <= 0;
            shift_reg <= 8'b0;
        end else if (baud_rate_clock) begin
            case (state)
                IDLE: begin
                    tx <= 1'b1;
                    tx_done <= 1'b0;
                    if (tx_start) begin
                        state <= START;
                        shift_reg <= data_in;
                        tick_counter <= 0;
                    end
                end

                START: begin
                    tx <= 1'b0;
                    if (tick_counter == 15) begin
                        state <= DATA;
                        tick_counter <= 0;
                        bit_counter <= 0;
                    end else begin
                        tick_counter <= tick_counter + 1;
                    end
                end

                DATA: begin
                    tx <= shift_reg[0];
                    if (tick_counter == 15) begin
                        tick_counter <= 0;
                        if (bit_counter == DATA_BITS - 1) begin
                            state <= STOP;
                        end else begin
                            bit_counter <= bit_counter + 1;
                            shift_reg <= {1'b0, shift_reg[7:1]};
                        end
                    end else begin
                        tick_counter <= tick_counter + 1;
                    end
                end

                STOP: begin
                    tx <= 1'b1;
                    if (tick_counter == 15) begin
                        state <= IDLE;
                        tx_done <= 1'b1;
                    end else begin
                        tick_counter <= tick_counter + 1;
                    end
                end

                default: state <= IDLE;
            endcase
        end
    end

endmodule

files.origen_124154.v:
module origen_124154 (
    input wire clk,
    input wire reset,
    input wire [1:0] product_select,
    input wire [1:0] coin_insert,
    input wire dispense,
    output reg coin_return,
    output reg product_dispensed,
    output reg [4:0] display_value
);

    // Product prices (in nickels)
    parameter PRODUCT1_PRICE = 5'd10;  // 50 cents
    parameter PRODUCT2_PRICE = 5'd14;  // 70 cents
    parameter PRODUCT3_PRICE = 5'd18;  // 90 cents
    parameter PRODUCT4_PRICE = 5'd20;  // 100 cents

    // State definitions
    parameter IDLE = 2'b00;
    parameter COIN_INSERTED = 2'b01;
    parameter DISPENSE_PRODUCT = 2'b10;
    parameter RETURN_CHANGE = 2'b11;

    reg [1:0] current_state, next_state;
    reg [4:0] inserted_amount;
    reg [4:0] selected_price;

    // State transition logic
    always @(posedge clk or posedge reset) begin
        if (reset)
            current_state <= IDLE;
        else
            current_state <= next_state;
    end

    // Next state and output logic
    always @(*) begin
        next_state = current_state;
        coin_return = 1'b0;
        product_dispensed = 1'b0;

        case (current_state)
            IDLE: begin
                if (coin_insert != 2'b00)
                    next_state = COIN_INSERTED;
            end

            COIN_INSERTED: begin
                if (inserted_amount >= selected_price && dispense)
                    next_state = DISPENSE_PRODUCT;
                else if (coin_insert != 2'b00)
                    next_state = COIN_INSERTED;
            end

            DISPENSE_PRODUCT: begin
                product_dispensed = 1'b1;
                if (inserted_amount > selected_price)
                    next_state = RETURN_CHANGE;
                else
                    next_state = IDLE;
            end

            RETURN_CHANGE: begin
                coin_return = 1'b1;
                next_state = IDLE;
            end
        endcase
    end

    // Update inserted amount and selected price
    always @(posedge clk or posedge reset) begin
        if (reset) begin
            inserted_amount <= 5'd0;
            selected_price <= PRODUCT1_PRICE;
        end else begin
            case (current_state)
                IDLE: begin
                    inserted_amount <= 5'd0;
                    case (product_select)
                        2'b00: selected_price <= PRODUCT1_PRICE;
                        2'b01: selected_price <= PRODUCT2_PRICE;
                        2'b10: selected_price <= PRODUCT3_PRICE;
                        2'b11: selected_price <= PRODUCT4_PRICE;
                    endcase
                end

                COIN_INSERTED: begin
                    case (coin_insert)
                        2'b00: inserted_amount <= inserted_amount + 5'd1;  // Nickel
                        2'b01: inserted_amount <= inserted_amount + 5'd2;  // Dime
                        2'b10: inserted_amount <= inserted_amount + 5'd5;  // Quarter
                        default: inserted_amount <= inserted_amount;
                    endcase
                end

                DISPENSE_PRODUCT: begin
                    inserted_amount <= (inserted_amount > selected_price) ? (inserted_amount - selected_price) : 5'd0;
                end

                RETURN_CHANGE: begin
                    inserted_amount <= 5'd0;
                end
            endcase
        end
    end

    // Update display value
    always @(posedge clk or posedge reset) begin
        if (reset)
            display_value <= 5'd0;
        else
            display_value <= inserted_amount;
    end

endmodule

