module origen_151835(
    input red_trffc_light,
    input ylw_trffc_light,
    input grn_trffc_light,
    input cross_button,
    input reset,
    input clk,
    output walk_light,
    output stop_light,
    output cross_rqst,
    output debug_q
);

    reg [7:0] timer;
    reg [1:0] state;
    reg [1:0] light;
    reg Q;
    reg blink_red;
    reg blink_flag;
    reg white_flag;
    reg useless1;
    reg useless2;

    localparam STATE_RED = 2'b00;
    localparam STATE_WHITE = 2'b01;
    localparam STATE_BLINK_RED = 2'b10;
    localparam STATE_ERROR = 2'b11;

    always @(posedge clk or posedge reset) begin
        if (reset) begin
            state <= STATE_RED;
            light <= 2'b01;
            Q <= 1'b0;
            blink_red <= 1'b0;
            blink_flag <= 1'b0;
            white_flag <= 1'b1;
            timer <= 8'b0;
        end
        else begin
            case (state)
                STATE_RED: begin
                    if (cross_button) begin
                        Q <= 1'b1;
                    end
                    else begin
                        Q <= 1'b0;
                    end
                    light <= 2'b01;
                    blink_red <= 1'b0;
                    white_flag <= 1'b0;
                    if (red_trffc_light) begin
                        state <= STATE_WHITE;
                        timer <= 8'b11111111;
                    end
                    else begin
                        state <= STATE_ERROR;
                    end
                end
                STATE_WHITE: begin
                    Q <= 1'b0;
                    light <= 2'b10;
                    blink_red <= 1'b0;
                    white_flag <= 1'b1;
                    if (timer == 8'b0) begin
                        state <= STATE_BLINK_RED;
                        timer <= 8'b00001010;
                    end
                    else begin
                        timer <= timer - 1'b1;
                    end
                end
                STATE_BLINK_RED: begin
                    Q <= 1'b0;
                    light[0] <= ~blink_flag;
                    blink_red <= 1'b1;
                    white_flag <= 1'b0;
                    if (timer == 8'b0) begin
                        state <= STATE_RED;
                    end
                    else begin
                        timer <= timer - 1'b1;
                        blink_flag <= ~blink_flag;
                    end
                end
                STATE_ERROR: begin
                    Q <= 1'b0;
                    light <= 2'b11;
                    blink_red <= 1'b1;
                    white_flag <= 1'b0;
                    if (red_trffc_light) begin
                        state <= STATE_RED;
                    end
                end
                default: begin
                    state <= STATE_ERROR;
                end
            endcase
        end
    end

    assign walk_light = white_flag;
    assign stop_light = light[0] | (~white_flag & blink_red);
    assign cross_rqst = Q;
    assign debug_q = Q;

endmodule

files.origen_136391.v:
module origen_136391 (
    // Host interface
    input wire clk,
    input wire rst,
    input wire [47:0] host_cmd,
    input wire [31:0] host_dat_in,
    input wire host_cmd_en,
    input wire host_dat_en,
    input wire host_dat_dir,
    input wire host_dat_ack,
    output reg host_cmd_ack,
    output reg host_dat_rdy,
    output reg [31:0] host_dat_out,

    // Device interface
    input wire [47:0] device_cmd,
    input wire [31:0] device_dat_in,
    input wire device_cmd_en,
    input wire device_dat_en,
    input wire device_dat_dir,
    input wire device_dat_ack,
    output reg device_cmd_ack,
    output reg device_dat_rdy,
    output reg [31:0] device_dat_out
);

// States
localparam IDLE = 3'b000;
localparam INIT = 3'b001;
localparam CMD  = 3'b010;
localparam DATA = 3'b011;
localparam RESP = 3'b100;

reg [2:0] state, next_state;
reg [9:0] block_counter;
reg [47:0] cmd_buffer;
reg [31:0] dat_buffer;

// State machine
always @(posedge clk or posedge rst) begin
    if (rst) begin
        state <= IDLE;
    end else begin
        state <= next_state;
    end
end

// Next state logic
always @(*) begin
    case (state)
        IDLE: next_state = (host_cmd_en || device_cmd_en) ? INIT : IDLE;
        INIT: next_state = CMD;
        CMD:  next_state = (host_cmd_en || device_cmd_en) ? RESP : CMD;
        RESP: next_state = (host_dat_en || device_dat_en) ? DATA : IDLE;
        DATA: next_state = (block_counter == 10'd511) ? IDLE : DATA;
        default: next_state = IDLE;
    endcase
end

// Command handling
always @(posedge clk) begin
    if (state == CMD) begin
        if (host_cmd_en) begin
            cmd_buffer <= host_cmd;
            host_cmd_ack <= 1'b1;
        end else if (device_cmd_en) begin
            cmd_buffer <= device_cmd;
            device_cmd_ack <= 1'b1;
        end
    end else begin
        host_cmd_ack <= 1'b0;
        device_cmd_ack <= 1'b0;
    end
end

// Data handling
always @(posedge clk) begin
    if (state == DATA) begin
        if (host_dat_en && host_dat_dir) begin
            dat_buffer <= host_dat_in;
            device_dat_out <= host_dat_in;
            device_dat_rdy <= 1'b1;
        end else if (device_dat_en && !device_dat_dir) begin
            dat_buffer <= device_dat_in;
            host_dat_out <= device_dat_in;
            host_dat_rdy <= 1'b1;
        end

        if (block_counter == 10'd511) begin
            block_counter <= 10'd0;
        end else begin
            block_counter <= block_counter + 1'b1;
        end
    end else begin
        host_dat_rdy <= 1'b0;
        device_dat_rdy <= 1'b0;
        block_counter <= 10'd0;
    end
end

// Initialization sequence (simplified)
reg [3:0] init_counter;
always @(posedge clk) begin
    if (state == INIT) begin
        if (init_counter < 4'd10) begin
            init_counter <= init_counter + 1'b1;
        end else begin
            init_counter <= 4'd0;
        end
    end else begin
        init_counter <= 4'd0;
    end
end

endmodule

