module autovcoder_069231 (

    input wire clk,
    input wire rst,
    input wire [3:0] priv,  //当前机器权限状态

    //中断控制器信号
    input wire int_req,			//中断请求信号，当准备处理中断时为1请求,中断请求信号在IF阶段被插入，只有当机器确保流水线排空之后才会处理中断
    //pip控制器信号
