    output wire [63:0] addr,

    output wire rd,  //取指令信号
    output wire [3:0] if_priv,
    input wire [63:0] ins_in,
    input wire ins_acc_fault_biu,  //指令访问失败
    input wire ins_page_fault_biu,  //指令页面错误
